def reciprocal_rank(retrieved: list[Document], relevant_ids: set[str]) -> float:
    """Return 1/rank of first relevant document; 0 if none found."""
    for rank, doc in enumerate(retrieved, start=1):
        if doc.metadata.get("doc_id") in relevant_ids:
            return 1.0 / rank
    return 0.0

def mean_reciprocal_rank(
    test_cases: list[dict], retriever, k: int = 10
) -> float:
    rrs = []
    for case in test_cases:
        docs = retriever.invoke(case["query"])[:k]
        rrs.append(reciprocal_rank(docs, set(case["relevant_ids"])))
    return sum(rrs) / len(rrs) if rrs else 0.0

mrr = mean_reciprocal_rank(test_cases, retriever, k=10)
print(f"MRR@10: {mrr:.3f}")

def hit_rate_at_k(
    test_cases: list[dict], retriever, k: int = 5
) -> float:
    """Fraction of queries where at least one relevant doc is in top-k."""
    hits = 0
    for case in test_cases:
        docs = retriever.invoke(case["query"])[:k]
        retrieved_ids = {doc.metadata.get("doc_id") for doc in docs}
        if retrieved_ids & set(case["relevant_ids"]):
            hits += 1
    return hits / len(test_cases) if test_cases else 0.0

hr = hit_rate_at_k(test_cases, retriever, k=3)
print(f"Hit rate@3: {hr:.2f}")
# A hit rate < 0.8 usually means retrieval is the bottleneck.
